clc;
clear;
data = input('Enter the data values as a vector [ ]: ');
AM = mean(data);
MED = median(data);
MOD = mode(data);
if all(data > 0)
    GM = geomean(data);
else
    GM = NaN;
    disp('Geometric mean not defined for non-positive data.');
end
if all(data ~= 0)
    HM = harmmean(data);
else
    HM = NaN;
    disp('Harmonic mean not defined when data contains zero.');
end
fprintf('\nMeasures of Central Tendency:\n');
fprintf('Arithmetic Mean = %.4f\n', AM);
fprintf('Median = %.4f\n', MED);
fprintf('Mode = %.4f\n', MOD);
fprintf('Geometric Mean = %.4f\n', GM);
fprintf('Harmonic Mean = %.4f\n', HM);
means = [AM, MED, MOD, GM, HM];
labels = {'AM', 'Median', 'Mode', 'GM', 'HM'};
figure;
bar(means);
set(gca, 'XTickLabel', labels);
xlabel('Measure Type');
ylabel('Value');
title('Comparison of Measures of Central Tendency');
grid on;
for i = 1:length(means)
    text(i, means(i), sprintf('%.2f', means(i)),'HorizontalAlignment', 'center','VerticalAlignment', 'bottom','FontSize', 10, 'FontWeight', 'bold');
end

clc;
clear;
data = input('Enter the data values as a vector [ ]: ');
n = length(data);
Range = max(data) - min(data);
Q1 = prctile(data, 25);
Q3 = prctile(data, 75);
QD = (Q3 - Q1) / 2;
MeanVal = mean(data);
MD = sum(abs(data - MeanVal)) / n;
SD = std(data);
VAR = var(data);
fprintf('\nMeasures of Dispersion:\n');
fprintf('Range = %.4f\n', Range);
fprintf('Quartile Deviation = %.4f\n', QD);
fprintf('Mean Deviation = %.4f\n', MD);
fprintf('Standard Deviation = %.4f\n', SD);
fprintf('Variance = %.4f\n', VAR);
dispersionValues = [Range, QD, MD, SD, VAR];
labels = {'Range', 'QD', 'MD', 'SD', 'Variance'};
figure;
bar(dispersionValues);
set(gca, 'XTickLabel', labels);
xlabel('Dispersion Measure');
ylabel('Value');
title('Comparison of Measures of Dispersion');
grid on;
for i = 1:length(dispersionValues)
    text(i, dispersionValues(i), sprintf('%.2f', dispersionValues(i)), 'HorizontalAlignment', 'center','VerticalAlignment', 'bottom','FontSize', 10, 'FontWeight', 'bold');
end

