clear;
close all;
syms x y
f = x^2 + y^2;
g = 2*x + y;
grad_f = gradient(f, [x y]);
grad_g = gradient(g, [x y]);
x0 = 1;
y0 = 1;
N1 = double(subs(grad_f, [x y], [x0 y0]));
N2 = double(subs(grad_g, [x y], [x0 y0]));
theta = acosd(dot(N1, N2) / (norm(N1) * norm(N2)));
fprintf('Angle between the two surfaces at (%.2f, %.2f) = %.2f degrees\n', x0, y0, theta);
[X, Y] = meshgrid(-3:0.2:3, -3:0.2:3);
Z1 = X.^2 + Y.^2;
Z2 = 2*X + Y;
figure;
surf(X, Y, Z1, 'FaceAlpha', 0.6);
hold on;
surf(X, Y, Z2, 'FaceAlpha', 0.6);
z1p = x0^2 + y0^2;
z2p = 2*x0 + y0;
quiver3(x0, y0, z1p, N1(1), N1(2), -1, 'k', 'LineWidth', 2);
quiver3(x0, y0, z2p, N2(1), N2(2), -1, 'r', 'LineWidth', 2);
legend('Surface 1', 'Surface 2', 'Normal to Surface 1', 'Normal to Surface 2');
title('Angle Between Two Surfaces at a Point');
xlabel('x');
ylabel('y');
zlabel('z');
grid on;
view(3);

