if any(x <= 0) || any(y <= 0)
    error('Both x and y values must be positive for power-law fitting.');
end
X = log(x);
Y = log(y);
n = length(x);
Sx = sum(X);
Sy = sum(Y);
Sxx = sum(X.^2);
Sxy = sum(X.*Y);
A = [Sxx Sx; Sx n];
B = [Sxy; Sy];
coeff = A \ B;
b = coeff(1);
ln_a = coeff(2);
a = exp(ln_a);
fprintf('\nBest fit curve: y = %.4f x^{%.4f}\n', a, b);
y_fit = a * x.^b;
figure;
plot(x, y, 'o', 'MarkerSize', 8, 'LineWidth', 2);
hold on;
plot(x, y_fit, '-', 'LineWidth', 2);
grid on;
